const STATE_VERSION = 'shouting-man-voice-v1';
const SHOUT_INTERVAL_SECONDS = 20;

export default function setup(ctx, prevState) {
  const audio = ctx.audioCtx;
  const clamp = (value, min, max) => Math.max(min, Math.min(max, value));
  const finite = (value, fallback) => Number.isFinite(value) ? value : fallback;
  const previousMatches = prevState?.stateVersion === STATE_VERSION;

  const state = {
    stateVersion: STATE_VERSION,
    enabled: previousMatches ? prevState.enabled !== false : true,
    volume: previousMatches ? finite(prevState.volume, 0.46) : 0.46,
    grit: previousMatches ? finite(prevState.grit, 0.72) : 0.72
  };

  let nextShoutAt = audio.currentTime + SHOUT_INTERVAL_SECONDS;
  let timer = 0;
  let raf = 0;
  let pulse = 0;
  let lastShoutLabel = 'waiting';
  const liveNodes = new Set();

  const output = audio.createGain();
  const compressor = audio.createDynamicsCompressor();
  const dry = audio.createGain();
  const send = audio.createGain();
  const delay = audio.createDelay(0.8);
  const feedback = audio.createGain();
  const wet = audio.createGain();

  output.gain.value = state.enabled ? state.volume : 0;
  compressor.threshold.value = -18;
  compressor.knee.value = 14;
  compressor.ratio.value = 5;
  compressor.attack.value = 0.004;
  compressor.release.value = 0.16;
  dry.gain.value = 0.88;
  send.gain.value = 0.18;
  delay.delayTime.value = 0.13;
  feedback.gain.value = 0.2;
  wet.gain.value = 0.25;

  output.connect(compressor);
  compressor.connect(ctx.audioOut);
  delay.connect(feedback);
  feedback.connect(delay);
  delay.connect(wet);
  wet.connect(output);

  ctx.domRoot.innerHTML = `
    <style>
