        background:
          radial-gradient(circle at 50% 105%, rgba(239, 68, 68, 0.24), transparent 44%),
          linear-gradient(135deg, rgba(24, 24, 27, 0.97), rgba(48, 36, 28, 0.97) 58%, rgba(18, 20, 24, 0.97));
        border: 1px solid rgba(248, 113, 113, 0.46);
        border-radius: 8px;
        font: 11px/1.32 ui-monospace, SFMono-Regular, Menlo, Consolas, monospace;
      }
      .top {
        display: grid;
        grid-template-columns: minmax(0, 1fr) auto auto;
        gap: 7px;
        align-items: center;
      }
      h1 {
        margin: 0;
        color: #fecaca;
        font: 700 12px/1 ui-sans-serif, system-ui, sans-serif;
        letter-spacing: 0;
      }
      .sub {
        margin-top: 3px;
        color: #a1a1aa;
        font-size: 10px;
        overflow: hidden;
        text-overflow: ellipsis;
        white-space: nowrap;
      }
      button {
        height: 28px;
        min-width: 42px;
        padding: 0 9px;
        border: 1px solid rgba(248, 113, 113, 0.62);
        border-radius: 5px;
        color: #1f0909;
        background: #f87171;
        font: inherit;
        cursor: pointer;
      }
      button.off {
        color: #d4d4d8;
        background: rgba(39, 39, 42, 0.82);
        border-color: rgba(161, 161, 170, 0.34);
      }
      .controls {
        display: grid;
        gap: 6px;
      }
      label {
        min-width: 0;
        display: grid;
        grid-template-columns: 56px minmax(0, 1fr) 34px;
        gap: 7px;
        align-items: center;
        color: #e7e5e4;
      }
      input[type="range"] {
        width: 100%;
        min-width: 0;
        accent-color: #f87171;
      }
      .stage {
        min-height: 84px;
        padding: 10px;
        display: grid;
        grid-template-columns: 1fr auto;
        align-items: end;
        gap: 8px;
        overflow: hidden;
        border: 1px solid rgba(248, 113, 113, 0.34);
        background:
          radial-gradient(circle at 42% 45%, rgba(254, 202, 202, calc(0.2 + var(--pulse) * 0.55)), transparent calc(22% + var(--pulse) * 17%)),
          linear-gradient(180deg, rgba(7, 7, 9, 0.34), rgba(12, 10, 9, 0.76));
      }
      .word {
        color: #fff7ed;
        font: 800 34px/0.9 ui-sans-serif, system-ui, sans-serif;
        letter-spacing: 0;
        transform: translateY(calc(var(--pulse) * -7px)) scale(calc(1 + var(--pulse) * 0.08));
        transform-origin: left bottom;
        text-shadow: 0 0 calc(8px + var(--pulse) * 18px) rgba(248, 113, 113, 0.74);
      }
      .meter {
        width: 44px;
