        display: grid;
        align-items: end;
        border-left: 1px solid rgba(248, 113, 113, 0.26);
        padding-left: 8px;
      }
      .bar {
        width: 100%;
        height: calc(8px + var(--pulse) * 44px);
        background: linear-gradient(180deg, #fed7aa, #ef4444);
        box-shadow: 0 0 14px rgba(239, 68, 68, 0.52);
      }
      .status {
        color: #a8a29e;
        font-size: 10px;
        white-space: nowrap;
        overflow: hidden;
        text-overflow: ellipsis;
      }
    </style>
    <div class="root">
      <div class="top">
        <div>
          <h1>SHOUTING MAN</h1>
          <div class="sub">synthetic voice every 20 sec</div>
        </div>
        <button id="trigger" type="button">shout</button>
        <button id="enabled" type="button"></button>
      </div>
      <div class="controls">
        <label>volume <input id="volume" type="range" min="0" max="0.9" step="0.01"><span id="volumeVal"></span></label>
        <label>grit <input id="grit" type="range" min="0" max="1" step="0.01"><span id="gritVal"></span></label>
      </div>
      <div id="stage" class="stage" style="--pulse:0">
        <div>
          <div id="word" class="word">HEY!</div>
          <div id="status" class="status">next shout in 20.0s</div>
        </div>
        <div class="meter"><div class="bar"></div></div>
      </div>
    </div>
  `;

  const $ = (selector) => ctx.domRoot.querySelector(selector);
  const enabledButton = $('#enabled');
  const triggerButton = $('#trigger');
  const stage = $('#stage');
  const status = $('#status');
  const word = $('#word');
  const sliders = {
    volume: $('#volume'),
    grit: $('#grit')
  };
  const values = {
    volume: $('#volumeVal'),
    grit: $('#gritVal')
  };

  function trackNode(node) {
    liveNodes.add(node);
    return node;
  }

  function cleanupNode(node) {
    try { node.stop?.(); } catch (_) {}
    try { node.disconnect?.(); } catch (_) {}
    liveNodes.delete(node);
  }

  function makeNoiseBuffer(seconds) {
    const length = Math.max(1, Math.floor(audio.sampleRate * seconds));
    const buffer = audio.createBuffer(1, length, audio.sampleRate);
    const data = buffer.getChannelData(0);
    let held = 0;
    for (let i = 0; i < length; i += 1) {
      if (i % 7 === 0) held = Math.random() * 2 - 1;
      data[i] = held * (1 - i / length) * 0.86;
    }
    return buffer;
  }

  function connectFormant(source, destination, frequency, gainValue, qValue) {
    const filter = trackNode(audio.createBiquadFilter());
    const gain = trackNode(audio.createGain());
    filter.type = 'bandpass';
    filter.frequency.value = frequency;
    filter.Q.value = qValue;
    gain.gain.value = gainValue;
    source.connect(filter);
    filter.connect(gain);
    gain.connect(destination);
    return [filter, gain];
  }

  function scheduleParam(param, time, points) {
    param.cancelScheduledValues(time);
    points.forEach(([offset, value, mode], index) => {
      const at = time + offset;
      if (index === 0 || mode === 'set') param.setValueAtTime(value, at);
      else if (mode === 'exp') param.exponentialRampToValueAtTime(Math.max(0.0001, value), at);
      else param.linearRampToValueAtTime(value, at);
    });
  }

  function scheduleShout(when = audio.currentTime + 0.03) {
    if (!state.enabled) return;

    const start = Math.max(audio.currentTime + 0.02, when);
    const duration = 1.12;
    const grit = clamp(state.grit, 0, 1);
    const syllables = ['HEY!', 'HAH!', 'YO!'];
    lastShoutLabel = syllables[Math.floor(Math.random() * syllables.length)];
    word.textContent = lastShoutLabel;
    pulse = 1;

    const voiceBus = trackNode(audio.createGain());
    const mouth = trackNode(audio.createGain());
    const voiceLow = trackNode(audio.createOscillator());
    const voiceMid = trackNode(audio.createOscillator());
    const rough = trackNode(audio.createOscillator());
    const noise = trackNode(audio.createBufferSource());
    const noiseGain = trackNode(audio.createGain());
    const noiseFilter = trackNode(audio.createBiquadFilter());
    const chest = trackNode(audio.createBiquadFilter());
    const shaper = trackNode(audio.createWaveShaper());
    const pan = trackNode(audio.createStereoPanner());

    const curve = new Float32Array(512);
    const drive = 1.8 + grit * 4.2;
    for (let i = 0; i < curve.length; i += 1) {
      const x = (i / (curve.length - 1)) * 2 - 1;
      curve[i] = Math.tanh(x * drive);
    }

    voiceLow.type = 'sawtooth';
    voiceMid.type = 'square';
    rough.type = 'sawtooth';
    noise.buffer = makeNoiseBuffer(duration);
    noiseFilter.type = 'bandpass';
    noiseFilter.frequency.value = 1850 + grit * 950;
    noiseFilter.Q.value = 1.1;
    chest.type = 'lowshelf';
    chest.frequency.value = 220;
    chest.gain.value = 7;
    shaper.curve = curve;
    shaper.oversample = '2x';
    pan.pan.value = -0.1 + Math.random() * 0.2;

    scheduleParam(voiceLow.frequency, start, [
      [0, 138 + grit * 20, 'set'],
      [0.08, 118, 'linear'],
      [0.52, 86, 'linear'],
      [duration, 72, 'linear']
    ]);
    scheduleParam(voiceMid.frequency, start, [
      [0, 276 + grit * 42, 'set'],
      [0.08, 236, 'linear'],
      [0.52, 172, 'linear'],
      [duration, 144, 'linear']
    ]);
    scheduleParam(rough.frequency, start, [
      [0, 45 + grit * 18, 'set'],
      [duration, 34, 'linear']
    ]);

    scheduleParam(voiceBus.gain, start, [
      [0, 0.0001, 'set'],
      [0.025, 0.92, 'exp'],
      [0.16, 0.78, 'linear'],
      [0.52, 0.66, 'linear'],
      [0.92, 0.24, 'linear'],
      [duration, 0.0001, 'exp']
    ]);
    scheduleParam(noiseGain.gain, start, [
      [0, 0.0001, 'set'],
      [0.02, 0.2 + grit * 0.34, 'exp'],
      [0.16, 0.14 + grit * 0.14, 'linear'],
      [0.7, 0.07, 'linear'],
      [duration, 0.0001, 'exp']
    ]);

    voiceLow.connect(voiceBus);
    voiceMid.connect(voiceBus);
    rough.connect(voiceBus.gain);
    noise.connect(noiseFilter);
    noiseFilter.connect(noiseGain);
    noiseGain.connect(mouth);
    voiceBus.connect(mouth);

    const vowel = lastShoutLabel === 'YO!'
      ? [[420, 0.98, 8], [840, 0.48, 8], [2450, 0.16, 7]]
      : [[730, 1.0, 7], [1160, 0.5, 8], [2580 + grit * 430, 0.18, 7]];
    vowel.flatMap(([frequency, gainValue, qValue]) => connectFormant(mouth, chest, frequency, gainValue, qValue));

    chest.connect(shaper);
    shaper.connect(pan);
    pan.connect(dry);
    pan.connect(send);
    dry.connect(output);
    send.connect(delay);

    [voiceLow, voiceMid, rough, noise].forEach((node) => node.start(start));
    [voiceLow, voiceMid, rough, noise].forEach((node) => node.stop(start + duration + 0.05));

    const stopAt = start + duration + 0.4;
    window.setTimeout(() => {
      [
        voiceLow, voiceMid, rough, noise, voiceBus, mouth, noiseGain,
        noiseFilter, chest, shaper, pan
      ].forEach(cleanupNode);
    }, Math.max(0, (stopAt - audio.currentTime) * 1000));
  }

  function render() {
    enabledButton.textContent = state.enabled ? 'on' : 'off';
    enabledButton.classList.toggle('off', !state.enabled);
    triggerButton.disabled = !state.enabled;
    output.gain.setTargetAtTime(state.enabled ? state.volume : 0, audio.currentTime, 0.02);

    sliders.volume.value = String(state.volume);
    sliders.grit.value = String(state.grit);
    values.volume.textContent = String(Math.round(state.volume * 100));
    values.grit.textContent = String(Math.round(state.grit * 100));

    const remaining = Math.max(0, nextShoutAt - audio.currentTime);
    status.textContent = state.enabled
      ? `next shout in ${remaining.toFixed(1)}s`
      : `paused, next shout in ${remaining.toFixed(1)}s`;
    stage.style.setProperty('--pulse', String(clamp(pulse, 0, 1)));
  }

  function scheduleNext(fromTime = audio.currentTime) {
    nextShoutAt = fromTime + SHOUT_INTERVAL_SECONDS;
    if (timer) window.clearTimeout(timer);
    timer = window.setTimeout(onTimer, SHOUT_INTERVAL_SECONDS * 1000);
    render();
  }

  function onTimer() {
    scheduleShout(audio.currentTime + 0.03);
    scheduleNext(audio.currentTime);
  }

  function animate() {
    pulse *= 0.9;
    render();
    raf = window.requestAnimationFrame(animate);
  }

  function onEnabledClick() {
    state.enabled = !state.enabled;
    if (state.enabled && nextShoutAt < audio.currentTime) scheduleNext(audio.currentTime);
    render();
  }

  function onTriggerClick() {
    scheduleShout(audio.currentTime + 0.03);
    scheduleNext(audio.currentTime);
  }

